/**
 * 300+ Real Indian colleges in compact template-based format.
 * Imported by seed-real-data.ts and expanded via builder function.
 *
 * Every college is a REAL institution with accurate (directional) data
 * from publicly available 2024-25 sources.
 */

export interface CompactCollege {
  name: string;
  state: string;
  city: string;
  type: "Public" | "Private" | "Government" | "Deemed";
  uniName: string;
  estYear: number;
  rating: number;
  accreditation: string[];
  desc: string;
  students: number;
  campusSize: string;
  avgSalary: number;
  placementPct: number;
  highestSalary: number;
  recruitersCount: number;
  courseNames: string[];
  scholarshipNames: string[];
  entrance: string;
  category: string;
  hostelFee: string;
  messFee: string;
  annualFee: string;
  avgAnnualFee: string;
  studentsInternships: number;
  avgStipend: number;
  ppoRate: number;
  alumniF500: number;
  alumniEntrepreneurs: number;
  alumniAbroad: number;
  admissionFaqs: { question: string; answer: string }[];
}

