/* Helper to merge template with per-college data */
function c(template: typeof T_IIT, data: Partial<CompactCollege> & Pick<CompactCollege, "name" | "state" | "city" | "uniName" | "estYear" | "rating" | "desc" | "students" | "campusSize" | "avgSalary" | "placementPct" | "highestSalary" | "recruitersCount" | "admissionFaqs">): CompactCollege {
  return { ...template, ...data } as CompactCollege;
}

